1	/**
2	 * Implement-loop engine — clockwork.
3	 *
4	 * Orchestrates sequential execution of piece writs under a mandate.
5	 *
6	 * On run:
7	 *   1. Queries all open child piece writs of the mandate.
8	 *   2. If pieces exist, grafts piece-session engines for each piece
9	 *      (in mandate child order) with sequential upstream dependencies.
10	 *   3. If no pieces exist, falls through to legacy single-session behavior
11	 *      identical to the original implement engine.
12	 *
13	 * The engine itself completes immediately with a graft (clockwork engine
14	 * returning { status: 'completed', yields, graft }). The grafted
15	 * piece-session engines are then processed sequentially by the Spider.
16	 *
17	 * For the legacy fallback (no pieces), it launches an anima session
18	 * directly, same as the original implement engine.
19	 */
20	
21	import { guild } from '@shardworks/nexus-core';
22	import type { EngineDesign, EngineRunResult } from '@shardworks/fabricator-apparatus';
23	import type { AnimatorApi } from '@shardworks/animator-apparatus';
24	import type { ClerkApi, WritDoc } from '@shardworks/clerk-apparatus';
25	import type { DraftYields, RigTemplateEngine, SpiderEngineRunResult } from '../types.ts';
26	import { EXECUTION_EPILOGUE } from './implement.ts';
27	
28	const implementLoopEngine: EngineDesign = {
29	  id: 'implement-loop',
30	
31	  async run(givens, context): Promise<EngineRunResult> {
32	    const clerk = guild().apparatus<ClerkApi>('clerk');
33	    const writ = givens.writ as WritDoc;
34	    const draft = context.upstream['draft'] as DraftYields;
35	
36	    // Query all open child piece writs of the mandate
37	    const pieces = await clerk.list({
38	      parentId: writ.id,
39	      type: 'piece',
40	      status: 'open',
41	      limit: 100,
42	    });
43	
44	    if (pieces.length === 0) {
45	      // ── Legacy fallback: no pieces → single-session implement ──
46	      const animator = guild().apparatus<AnimatorApi>('animator');
47	      const prompt = `${writ.body}\n${EXECUTION_EPILOGUE}`;
