content.content:
1	/**
2	 * The Oculus — web dashboard apparatus.
3	 *
4	 * Serves a web dashboard via Hono. Plugins contribute pages as static asset
5	 * directories and custom API routes through kit contributions. Guild tools are
6	 * automatically exposed as REST endpoints.
7	 */
8	
9	import fs from "node:fs";
10	import path from "node:path";
11	import { Hono } from "hono";
12	import { serve } from "@hono/node-server";
13	import type { Server } from "node:http";
14	import { z } from "zod";
15	
16	import type { Plugin, StartupContext } from "@shardworks/nexus-core";
17	import { guild, VERSION } from "@shardworks/nexus-core";
18	import type { InstrumentariumApi } from "@shardworks/tools-apparatus";
19	import { tool, isToolDefinition } from "@shardworks/tools-apparatus";
20	
21	import type {
22	  OculusApi,
23	  OculusConfig,
24	  OculusKit,
25	  PageContribution,
26	  RouteContribution,
27	} from "./types.ts";
28	
29	// ── MIME types ────────────────────────────────────────────────────────
30	
31	const MIME_TYPES: Record<string, string> = {
32	  ".html": "text/html; charset=utf-8",
33	  ".css": "text/css; charset=utf-8",
34	  ".js": "application/javascript; charset=utf-8",
35	  ".mjs": "application/javascript; charset=utf-8",
36	  ".json": "application/json; charset=utf-8",
37	  ".png": "image/png",
38	  ".jpg": "image/jpeg",
39	  ".jpeg": "image/jpeg",
40	  ".gif": "image/gif",
41	  ".svg": "image/svg+xml",
42	  ".ico": "image/x-icon",
43	  ".woff": "font/woff",
44	  ".woff2": "font/woff2",
45	  ".ttf": "font/ttf",
46	  ".map": "application/json",
47	};
48	
49	function getMimeType(filePath: string): string {
50	  const ext = path.extname(filePath).toLowerCase();
51	  return MIME_TYPES[ext] ?? "application/octet-stream";
52	}
53	
54	// ── Tool→REST mapping helpers ─────────────────────────────────────────
55	
56	export function toolNameToRoute(name: string): string {
57	  const idx = name.indexOf("-");
58	  if (idx === -1) return `/api/${name}`;
59	  return `/api/${name.slice(0, idx)}/${name.slice(idx + 1)}`;
60	}
61	
62	export function permissionToMethod(
63	  permission: string | undefined,
64	): "GET" | "POST" | "DELETE" {
65	  if (permission === undefined) return "GET";
66	  const level = permission.includes(":")
67	    ? permission.slice(permission.lastIndexOf(":") + 1)
68	    : permission;
69	  if (level === "read") return "GET";
70	  if (level === "write" || level === "admin") return "POST";
71	  if (level === "delete") return "DELETE";
72	  return "POST";
73	}
74	
75	// ── Query param coercion ──────────────────────────────────────────────
76	
77	function isNumberSchema(schema: z.ZodTypeAny): boolean {
78	  let inner: z.ZodTypeAny = schema;
79	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
80	  if (inner instanceof z.ZodDefault) inner = inner.unwrap() as z.ZodTypeAny;
81	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
82	  return inner instanceof z.ZodNumber;
83	}
84	
85	function isBooleanSchema(schema: z.ZodTypeAny): boolean {
86	  let inner: z.ZodTypeAny = schema;
87	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
88	  if (inner instanceof z.ZodDefault) inner = inner.unwrap() as z.ZodTypeAny;
89	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
90	  return inner instanceof z.ZodBoolean;
91	}
92	
93	export function isArrayAcceptingSchema(schema: z.ZodTypeAny): boolean {
94	  let inner: z.ZodTypeAny = schema;
95	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
96	  if (inner instanceof z.ZodDefault) inner = inner.unwrap() as z.ZodTypeAny;
97	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
98	  if (inner instanceof z.ZodArray) return true;
99	  if (inner instanceof z.ZodUnion) {
100	    return (inner.options as z.ZodTypeAny[]).some(
101	      (opt) => opt instanceof z.ZodArray,
102	    );
103	  }
104	  return false;
105	}
106	
107	/**
108	 * Parse URL query params, preserving repeated keys as arrays when the
109	 * Zod schema for that param accepts an array type.
110	 */
111	export function parseQueryParams(
112	  url: string,
113	  shape: Record<string, z.ZodTypeAny>,
114	): Record<string, unknown> {
115	  const searchParams = new URL(url, 'http://localhost').searchParams;
116	  const result: Record<string, unknown> = {};
117	  for (const key of new Set(searchParams.keys())) {
118	    const values = searchParams.getAll(key);
119	    if (values.length > 1 && shape[key] && isArrayAcceptingSchema(shape[key]!)) {
120	      result[key] = values;
121	    } else {
122	      result[key] = values[values.length - 1];
123	    }
124	  }
125	  return result;
126	}
127	
128	export function coerceParams(
129	  shape: Record<string, z.ZodTypeAny>,
130	  params: Record<string, string>,
131	): Record<string, unknown> {
132	  const result: Record<string, unknown> = { ...params };
133	  for (const [key, schema] of Object.entries(shape)) {
134	    const value = result[key];
135	    if (typeof value !== "string") continue;
136	    if (isNumberSchema(schema)) {
137	      result[key] = Number(value);
138	    } else if (isBooleanSchema(schema)) {
139	      result[key] = value === "true";
140	    }
141	  }
142	  return result;
143	}
144	
145	// ── Chrome injection ─────────────────────────────────────────────────
146	
147	export function injectChrome(
148	  html: string,
149	  stylesheetPath: string,
150	  navHtml: string,
151	): string {
152	  // Check for </head> case-insensitively
153	  const headCloseMatch = html.match(/<\/head>/i);
154	  const bodyOpenMatch = html.match(/<body[^>]*>/i);
155	
156	  // If neither tag present, return unmodified
157	  if (!headCloseMatch && !bodyOpenMatch) return html;
158	
159	  let result = html;
160	
161	  // Insert stylesheet link before </head>
162	  if (headCloseMatch && headCloseMatch.index !== undefined) {
163	    const idx = headCloseMatch.index;
164	    result =
165	      result.slice(0, idx) +
166	      `<link rel="stylesheet" href="${stylesheetPath}">` +
167	      result.slice(idx);
168	  }
169	
170	  // Insert nav after <body...>
171	  // Need to recalculate position after potential head insertion
172	  const bodyMatch = result.match(/<body[^>]*>/i);
173	  if (bodyMatch && bodyMatch.index !== undefined) {
174	    const idx = bodyMatch.index + bodyMatch[0].length;
175	    result = result.slice(0, idx) + navHtml + result.slice(idx);
176	  }
177	
178	  return result;
179	}
180	
181	function buildNavHtml(pages: PageContribution[]): string {
182	  const pageLinks = pages
183	    .map((p) => `<a href="/pages/${p.id}/">${p.title}</a>`)
184	    .join("\n  ");
185	  return `<nav id="oculus-nav">
186	  <a href="/">Guild</a>
187	  ${pageLinks}
188	</nav>`;
189	}
190	
191	// ── HTML escaping ─────────────────────────────────────────────────────
192	
193	function escapeHtml(text: string): string {
194	  return text
195	    .replace(/&/g, "&amp;")
196	    .replace(/</g, "&lt;")
197	    .replace(/>/g, "&gt;");
198	}
199	
200	// ── Tool param extraction (reimplemented from tools-show) ────────────
201	
202	interface ParamInfo {
203	  type: string;
204	  description: string | null;
205	  optional: boolean;
206	}
207	
208	function zodTypeToJsonType(zodType: z.ZodType): string {
209	  if (zodType instanceof z.ZodString) return "string";
210	  if (zodType instanceof z.ZodNumber) return "number";
211	  if (zodType instanceof z.ZodBoolean) return "boolean";
212	  if (zodType instanceof z.ZodArray) return "array";
213	  if (zodType instanceof z.ZodObject) return "object";
214	  if (zodType instanceof z.ZodEnum) return "string";
215	  if (zodType instanceof z.ZodLiteral) return typeof zodType._def.values[0];
216	  if (zodType instanceof z.ZodUnion) return "union";
217	  if (zodType instanceof z.ZodNullable)
218	    return zodTypeToJsonType(zodType.unwrap() as z.ZodType);
219	  return "unknown";
220	}
221	
222	function extractSingleParam(zodType: z.ZodType): ParamInfo {
223	  let isOptional = false;
224	  let inner: z.ZodType = zodType;
225	
226	  if (inner instanceof z.ZodOptional) {
227	    isOptional = true;
228	    inner = inner.unwrap() as z.ZodType;
229	  }
230	  if (inner instanceof z.ZodDefault) {
231	    isOptional = true;
232	    inner = inner.unwrap() as z.ZodType;
233	  }
234	
235	  return {
236	    type: zodTypeToJsonType(inner),
237	    description: inner.description ?? null,
238	    optional: isOptional,
239	  };
240	}
241	
242	function extractParams(
243	  schema: z.ZodObject<z.ZodRawShape>,
244	): Record<string, ParamInfo> {
245	  const shape = schema.shape;
246	  const result: Record<string, ParamInfo> = {};
247	  for (const [key, zodType] of Object.entries(shape)) {
248	    result[key] = extractSingleParam(zodType as z.ZodType);
249	  }
250	  return result;
251	}
252	
253	// ── Apparatus factory ─────────────────────────────────────────────────
254	
255	export function createOculus(): Plugin {
256	  let serverPort = 7470;
257	  let server: Server | null = null;
258	  let honoApp: Hono | null = null;
259	
260	  const api: OculusApi = {
261	    port(): number {
262	      return serverPort;
263	    },
264	    startServer(): Promise<void> {
265	      return startServer();
266	    },
267	    stopServer(): Promise<void> {
268	      return stopServer();
269	    },
270	  };
271	
272	  /** Start the HTTP server (called explicitly via the oculus tool). */
273	  async function startServer(): Promise<void> {
274	    if (server) return; // already running
275	    if (!honoApp)
276	      throw new Error(
277	        "[oculus] Cannot start server — apparatus not initialized",
278	      );
279	
280	    const app = honoApp;
281	    const port = serverPort;
282	    await new Promise<void>((resolve, reject) => {
283	      server = serve({ fetch: app.fetch, port }, () => {
284	        console.log(`[oculus] Listening on http://localhost:${port}`);
285	        resolve();
286	      }) as Server;
287	      server.on("error", reject);
288	    });
289	  }
290	
291	  /** Stop the HTTP server gracefully. Idempotent. */
292	  async function stopServer(): Promise<void> {
293	    if (!server) return;
294	    const s = server;
295	    server = null;
296	    await new Promise<void>((resolve, reject) => {
297	      s.close((err) => {
298	        if (err) reject(err);
299	        else resolve();
300	      });
301	    });
302	  }
303	
304	  return {
305	    apparatus: {
306	      requires: ["tools"],
307	      consumes: ["pages", "routes"],
308	      provides: api,
309	
310	      async start(ctx: StartupContext): Promise<void> {
311	        const g = guild();
312	        const oculusConfig: OculusConfig = g.guildConfig().oculus ?? {};
313	        serverPort = oculusConfig.port ?? 7470;
314	
315	        const app = new Hono();
316	        honoApp = app;
317	
318	        // Track registered pages and custom route paths
319	        const pages: PageContribution[] = [];
320	        const customRouteKeys = new Set<string>();
321	        const mappedToolRoutes = new Set<string>();
322	
323	        // ── Custom route registration helper ─────────────────────────
324	        function registerCustomRoute(
325	          route: RouteContribution,
326	          pluginId: string,
327	        ): void {
328	          if (!route.path.startsWith("/api/")) {
329	            console.warn(
330	              `[oculus] Custom route "${route.path}" from "${pluginId}" must start with /api/ — skipped`,
331	            );
332	            return;
333	          }
334	          const method = route.method.toLowerCase() as keyof typeof app;
335	          (
336	            app[method] as (
337	              path: string,
338	              handler: (c: unknown) => unknown,
339	            ) => void
340	          )(route.path, route.handler as (c: unknown) => unknown);
341	          customRouteKeys.add(`${route.method.toUpperCase()} ${route.path}`);
342	        }
343	
344	        // ── Page serving helper ───────────────────────────────────────
345	        function resolveDirForPackage(
346	          packageName: string,
347	          dir: string,
348	        ): string {
349	          return path.join(g.home, "node_modules", packageName, dir);
350	        }
351	
352	        function registerPage(
353	          page: PageContribution,
354	          resolvedDir: string,
355	        ): void {
356	          pages.push({ ...page });
357	
358	          app.get(`/pages/${page.id}/*`, async (c) => {
359	            const requestPath = c.req.path;
360	            const prefix = `/pages/${page.id}/`;
361	            const filePath = requestPath.slice(prefix.length) || "index.html";
362	
363	            // Prevent directory traversal
364	            if (filePath.includes("..")) {
365	              return c.text("Not found", 404);
366	            }
367	
368	            const absolutePath = path.join(resolvedDir, filePath);
369	
370	            // Ensure file is within resolved dir
371	            if (!absolutePath.startsWith(resolvedDir)) {
372	              return c.text("Not found", 404);
373	            }
374	
375	            try {
376	              const content = fs.readFileSync(absolutePath);
377	              const mimeType = getMimeType(absolutePath);
378	
379	              // Only inject chrome for the root index.html
380	              const isIndexHtml = filePath === "index.html" || filePath === "";
381	              if (isIndexHtml && mimeType.startsWith("text/html")) {
382	                const html = content.toString("utf-8");
383	                const navHtml = buildNavHtml(pages);
384	                const injected = injectChrome(
385	                  html,
386	                  "/static/style.css",
387	                  navHtml,
388	                );
389	                return new Response(injected, {
390	                  headers: { "Content-Type": "text/html; charset=utf-8" },
391	                });
392	              }
393	
394	              return new Response(content, {
395	                headers: { "Content-Type": mimeType },
396	              });
397	            } catch {
398	              return c.text("Not found", 404);
399	            }
400	          });
401	        }
402	
403	        // ── Tool route registration helper ───────────────────────────
404	        function registerToolRoute(
405	          toolDef: import("@shardworks/tools-apparatus").ToolDefinition,
406	        ): void {
407	          const routePath = toolNameToRoute(toolDef.name);
408	          const method = permissionToMethod(toolDef.permission);
409	
410	          if (mappedToolRoutes.has(routePath)) return;
411	
412	          if (customRouteKeys.has(`${method} ${routePath}`)) {
413	            console.warn(
414	              `[oculus] Tool route ${method} ${routePath} conflicts with custom route from plugin — skipped`,
415	            );
416	            return;
417	          }
418	
419	          const shape = toolDef.params.shape as Record<string, z.ZodTypeAny>;
420	
421	          if (method === "GET") {
422	            app.get(routePath, async (c) => {
423	              try {
424	                const rawQuery = parseQueryParams(c.req.url, shape);
425	                const coerced = coerceParams(shape, rawQuery as Record<string, string>);
426	                const validated = toolDef.params.parse(coerced);
427	                const result = await toolDef.handler(validated);
428	                return c.json(result);
429	              } catch (err) {
430	                if (err instanceof z.ZodError) {
431	                  return c.json(
432	                    { error: err.message, details: err.issues },
433	                    400,
434	                  );
435	                }
436	                const message =
437	                  err instanceof Error ? err.message : String(err);
438	                return c.json({ error: message }, 500);
439	              }
440	            });
441	          } else if (method === "DELETE") {
442	            app.delete(routePath, async (c) => {
443	              try {
444	                const body = await c.req.json();
445	                const validated = toolDef.params.parse(body);
446	                const result = await toolDef.handler(validated);
447	                return c.json(result);
448	              } catch (err) {
449	                if (err instanceof z.ZodError) {
450	                  return c.json(
451	                    { error: err.message, details: err.issues },
452	                    400,
453	                  );
454	                }
455	                const message =
456	                  err instanceof Error ? err.message : String(err);
457	                return c.json({ error: message }, 500);
458	              }
459	            });
460	          } else {
461	            app.post(routePath, async (c) => {
462	              try {
463	                const body = await c.req.json();
464	                const validated = toolDef.params.parse(body);
465	                const result = await toolDef.handler(validated);
466	                return c.json(result);
467	              } catch (err) {
468	                if (err instanceof z.ZodError) {
469	                  return c.json(
470	                    { error: err.message, details: err.issues },
471	                    400,
472	                  );
473	                }
474	                const message =
475	                  err instanceof Error ? err.message : String(err);
476	                return c.json({ error: message }, 500);
477	              }
478	            });
479	          }
480	
481	          mappedToolRoutes.add(routePath);
482	        }
483	
484	        // ── Register pages from all kit contributions ────────────────────
485	        for (const entry of ctx.kits("pages")) {
486	          for (const page of entry.value as PageContribution[]) {
487	            const resolvedDir = resolveDirForPackage(
488	              entry.packageName,
489	              page.dir,
490	            );
491	            registerPage(page, resolvedDir);
492	          }
493	        }
494	
495	        // ── Register custom routes from all kit contributions ────────────
496	        for (const entry of ctx.kits("routes")) {
497	          for (const route of entry.value as RouteContribution[]) {
498	            registerCustomRoute(route, entry.pluginId);
499	          }
500	        }
501	
502	        // ── Register tool routes from all kit contributions ──────────
503	        for (const entry of ctx.kits("tools")) {
504	          const rawTools = entry.value;
505	          if (!Array.isArray(rawTools)) continue;
506	          for (const t of rawTools) {
507	            if (
508	              isToolDefinition(t) &&
509	              (!t.callableBy || t.callableBy.includes("patron"))
510	            ) {
511	              registerToolRoute(t);
512	            }
513	          }
514	        }
515	
516	        // ── GET /api/_status ─────────────────────────────────────────
517	        app.get("/api/_status", (c) => {
518	          const config = g.guildConfig();
519	          return c.json({
520	            guild: config.name,
521	            nexus: VERSION,
522	            home: g.home,
523	            model: config.settings?.model ?? "(not set)",
524	            port: serverPort,
525	            apparatuses: g
526	              .apparatuses()
527	              .map((a) => ({ id: a.id, version: a.version })),
528	            kits: g.kits().map((k) => ({ id: k.id, version: k.version })),
529	            failedPlugins: g
530	              .failedPlugins()
531	              .map((f) => ({ id: f.id, reason: f.reason })),
532	            warnings: g.startupWarnings(),
533	            config: config,
534	          });
535	        });
536	
537	        // ── GET /api/_tools ──────────────────────────────────────────
538	        app.get("/api/_tools", (c) => {
539	          const instrumentarium = g.apparatus<InstrumentariumApi>("tools");
540	          const tools = instrumentarium
541	            .list()
542	            .filter(
543	              (r) =>
544	                !r.definition.callableBy ||
545	                r.definition.callableBy.includes("patron"),
546	            );
547	
548	          const entries = tools.map((r) => ({
549	            name: r.definition.name,
550	            route: toolNameToRoute(r.definition.name),
551	            method: permissionToMethod(r.definition.permission),
552	            description: r.definition.description,
553	            params: extractParams(r.definition.params),
554	          }));
555	
556	          return c.json(entries);
557	        });
558	
559	        // ── Static assets ────────────────────────────────────────────
560	        // In dev: import.meta.dirname = /packages/plugins/oculus/src
561	        // In prod: import.meta.dirname = /node_modules/@pkg/dist
562	        // Static files are always at src/static relative to package root
563	        const staticDir = path.resolve(import.meta.dirname, "../src/static");
564	
565	        app.get("/static/*", (c) => {
566	          const requestPath = c.req.path;
567	          const filePath = requestPath.slice("/static/".length);
568	
569	          if (filePath.includes("..")) {
570	            return c.text("Not found", 404);
571	          }
572	
573	          const absolutePath = path.join(staticDir, filePath);
574	          try {
575	            const content = fs.readFileSync(absolutePath);
576	            const mimeType = getMimeType(absolutePath);
577	            return new Response(content, {
578	              headers: { "Content-Type": mimeType },
579	            });
580	          } catch {
581	            return c.text("Not found", 404);
582	          }
583	        });
584	
585	        // ── Home page ────────────────────────────────────────────────
586	        app.get("/", (c) => {
587	          const config = g.guildConfig();
588	          const guildName = config.name;
589	          const navHtml = buildNavHtml(pages);
590	          const model = config.settings?.model ?? "(not set)";
591	
592	          // ── Identity card ──────────────────────────────────────────
593	          const identityCard = `<div class="card" style="margin-bottom: 16px;">
594	    <h2>Identity</h2>
595	    <table class="data-table">
596	      <tbody>
597	        <tr><td>Guild</td><td>${escapeHtml(guildName)}</td></tr>
598	        <tr><td>Nexus</td><td>${escapeHtml(VERSION)}</td></tr>
599	        <tr><td>Home</td><td>${escapeHtml(g.home)}</td></tr>
600	        <tr><td>Model</td><td>${escapeHtml(model)}</td></tr>
601	        <tr><td>Port</td><td>${serverPort}</td></tr>
602	      </tbody>
603	    </table>
604	  </div>`;
605	
606	          // ── Warnings card (conditional) ────────────────────────────
607	          const warnings = g.startupWarnings();
608	          const warningsCard =
609	            warnings.length > 0
610	              ? `<div class="card" style="margin-bottom: 16px;">
611	    <h2>Warnings</h2>
612	    <ul>
613	      ${warnings.map((w) => `<li><span class="badge badge--warning">${escapeHtml(w)}</span></li>`).join("\n      ")}
614	    </ul>
615	  </div>`
616	              : "";
617	
618	          // ── Plugins table ──────────────────────────────────────────
619	          const apparatuses = g.apparatuses();
620	          const kits = g.kits();
621	          const failedPlugins = g.failedPlugins();
622	
623	          let pluginRows = "";
624	          if (
625	            apparatuses.length === 0 &&
626	            kits.length === 0 &&
627	            failedPlugins.length === 0
628	          ) {
629	            pluginRows = `<tr><td colspan="4" class="empty-state">No plugins loaded.</td></tr>`;
630	          } else {
631	            pluginRows += apparatuses
632	              .map(
633	                (a) =>
634	                  `<tr>
635	          <td>${escapeHtml(a.id)}</td>
636	          <td>apparatus</td>
637	          <td>${escapeHtml(a.version)}</td>
638	          <td><span class="badge badge--success">apparatus</span></td>
639	        </tr>`,
640	              )
641	              .join("\n");
642	            pluginRows += kits
643	              .map(
644	                (k) =>
645	                  `<tr>
646	          <td>${escapeHtml(k.id)}</td>
647	          <td>kit</td>
648	          <td>${escapeHtml(k.version)}</td>
649	          <td><span class="badge badge--info">kit</span></td>
650	        </tr>`,
651	              )
652	              .join("\n");
653	            pluginRows += failedPlugins
654	              .map(
655	                (f) =>
656	                  `<tr>
657	          <td>${escapeHtml(f.id)}</td>
658	          <td>—</td>
659	          <td>—</td>
660	          <td><span class="badge badge--error" title="${escapeHtml(f.reason)}">failed</span> <span style="color: var(--text-dim); font-size: 11px;">${escapeHtml(f.reason)}</span></td>
661	        </tr>`,
662	              )
663	              .join("\n");
664	          }
665	
666	          const pluginsCard = `<div class="card" style="margin-bottom: 16px;">
667	    <h2>Plugins</h2>
668	    <table class="data-table">
669	      <thead>
670	        <tr><th>Id</th><th>Type</th><th>Version</th><th>Status</th></tr>
671	      </thead>
672	      <tbody>
673	        ${pluginRows}
674	      </tbody>
675	    </table>
676	  </div>`;
677	
678	          // ── Configuration card ─────────────────────────────────────
679	          let rawConfig = "";
680	          try {
681	            rawConfig = fs.readFileSync(
682	              path.join(g.home, "guild.json"),
683	              "utf-8",
684	            );
685	          } catch {
686	            rawConfig = "(unable to read guild.json)";
687	          }
688	
689	          const configCard = `<div class="card">
690	    <details>
691	      <summary>guild.json</summary>
692	      <pre class="config-block"><code>${escapeHtml(rawConfig)}</code></pre>
693	    </details>
694	  </div>`;
695	
696	          const html = `<!DOCTYPE html>
697	<html lang="en">
698	<head>
699	  <meta charset="UTF-8">
700	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
701	  <title>${escapeHtml(guildName)} — Guild Dashboard</title>
702	  <link rel="stylesheet" href="/static/style.css">
703	</head>
704	<body>
705	${navHtml}
706	<main style="padding: 24px;">
707	  <h1>${escapeHtml(guildName)}</h1>
708	  ${identityCard}
709	  ${warningsCard}
710	  ${pluginsCard}
711	  ${configCard}
712	</main>
713	</body>
714	</html>`;
715	
716	          return c.html(html);
717	        });
718	
719	        // Server is NOT started here — use the `oculus` tool to start it explicitly.
720	      },
721	
722	      async stop(): Promise<void> {
723	        await stopServer();
724	      },
725	
726	      supportKit: {
727	        tools: [
728	          tool({
729	            name: "oculus",
730	            description: "Start the Oculus web dashboard and keep it running",
731	            callableBy: ["patron"],
732	            params: {},
733	            handler: async () => {
734	              await api.startServer();
735	
736	              const port = api.port();
737	              console.log(
738	                `\n  Oculus is running at http://localhost:${port}/\n`,
739	              );
740	              console.log("  Press Ctrl+C to stop.\n");
741	
742	              // Block until the process is interrupted.
743	              await new Promise<void>((resolve) => {
744	                const onSignal = () => {
745	                  void api.stopServer().then(
746	                    () => resolve(),
747	                    () => resolve(),
748	                  );
749	                };
750	                process.once("SIGINT", onSignal);
751	                process.once("SIGTERM", onSignal);
752	              });
753	
754	              return "Oculus stopped.";
755	            },
756	          }),
757	        ],
758	      },
759	    },
760	  };
761	}
