140	  <script>
141	  (() => {
142	    // ── State ──────────────────────────────────────────────────────────
143	    let writs = [];          // root writs only (no parentId)
144	    let offset = 0;
145	    let currentStatus = '';  // '' = all
146	    let currentType = new Set();  // Set<string> — empty = no types selected (empty state)
147	    let searchText = '';
148	    let sortCol = 'createdAt';
149	    let sortDir = 'desc';
150	    let showChildren = true; // toggle state — children shown by default
151	    let childrenMap = {};    // { parentId: WritDoc[] } — fetched children keyed by parent id
