156	    // ── Helpers ────────────────────────────────────────────────────────
157	
158	    async function api(method, path, body) {
159	      const opts = { method, headers: { 'Content-Type': 'application/json' } };
160	      if (body !== undefined) opts.body = JSON.stringify(body);
161	      const res = await fetch(path, opts);
162	      const json = await res.json();
163	      if (!res.ok) throw new Error(json.error ?? `HTTP ${res.status}`);
164	      return json;
165	    }
166	
167	    function statusBadge(status) {
168	      const map = {
169	        new: 'badge badge--draft',
170	        open: 'badge badge--active',
171	        stuck: 'badge badge--warning',
172	        completed: 'badge badge--success',
173	        failed: 'badge badge--error',
174	        cancelled: 'badge badge--warning',
175	      };
176	      const cls = map[status] ?? 'badge';
177	      return `<span class="${cls}">${status}</span>`;
178	    }
179	
180	    function fmtDate(iso) {
181	      if (!iso) return '';
182	      return new Date(iso).toLocaleString();
183	    }
184	
185	    function compareVal(a, b, col) {
186	      const av = a[col] ?? '';
187	      const bv = b[col] ?? '';
188	      if (av < bv) return -1;
189	      if (av > bv) return 1;
190	      return 0;
191	    }
192	
193	    function sortedFilteredWrits() {
194	      let roots = writs.slice();
195	
196	      // Text filter on roots
197	      if (searchText) {
198	        const q = searchText.toLowerCase();
199	        roots = roots.filter(w => (w.title ?? '').toLowerCase().includes(q));
200	      }
201	
202	      // Sort roots by current sort column
203	      roots.sort((a, b) => {
204	        const cmp = compareVal(a, b, sortCol);
205	        return sortDir === 'asc' ? cmp : -cmp;
206	      });
207	
208	      // Interleave children beneath each root
209	      const result = [];
210	      for (const root of roots) {
211	        result.push({ writ: root, isChild: false });
212	        if (showChildren) {
213	          let children = childrenMap[root.id] ?? [];
214	          // Text filter on children too
215	          if (searchText) {
216	            const q = searchText.toLowerCase();
217	            children = children.filter(w => (w.title ?? '').toLowerCase().includes(q));
218	          }
219	          for (const child of children) {
220	            result.push({ writ: child, isChild: true });
221	          }
222	        }
223	      }
224	      return result;
225	    }
226	
227	    function showError(el, msg) {
228	      el.textContent = msg;
229	      el.style.display = 'block';
230	    }
231	
232	    function clearError(el) {
233	      el.textContent = '';
234	      el.style.display = 'none';
235	    }
236	
237	    // ── Row actions ────────────────────────────────────────────────────
238	
239	    /** Returns the HTML for the context-aware Actions cell for a writ row. */
240	    function rowActions(w) {
241	      const isTerminal = ['completed', 'failed', 'cancelled'].includes(w.status);
242	      const isStuck = w.status === 'stuck';
243	      if (isTerminal) return '';
244	      const btns = [];
245	      if (w.status === 'new') {
246	        btns.push(`<button class="btn btn--primary row-action-btn" style="padding:0.15rem 0.5rem;font-size:0.8rem" data-action="row-publish" data-id="${w.id}">Start</button>`);
247	      }
248	      btns.push(`<button class="btn btn--danger row-action-btn" style="padding:0.15rem 0.5rem;font-size:0.8rem" data-action="row-cancel" data-id="${w.id}">Cancel</button>`);
249	      return btns.join(' ');
250	    }
251	
252	    async function handleRowAction(action, id, btn) {
253	      const orig = btn.textContent;
254	      btn.disabled = true;
255	      try {
256	        if (action === 'row-publish') {
257	          btn.textContent = '…';
258	          await api('POST', '/api/writ/publish', { id });
259	        } else if (action === 'row-cancel') {
260	          btn.textContent = '…';
261	          await api('POST', '/api/writ/cancel', { id });
262	        }
263	        // Reload this writ and update the row
264	        const writ = await api('GET', `/api/writ/show?id=${encodeURIComponent(id)}`);
265	        const idx = writs.findIndex(w => w.id === id);
266	        if (idx >= 0) writs[idx] = writ;
267	        updateRowStatus(id);
268	        updateRowActions(id);
269	        // Refresh detail view if open
270	        if (document.getElementById('writ-detail-view').style.display !== 'none') {
271	          await refreshDetail(id);
272	        }
273	      } catch (e) {
274	        alert(`Action failed: ${e.message}`);
275	        btn.disabled = false;
276	        btn.textContent = orig;
277	      }
278	    }
279	
280	    function updateRowActions(id) {
281	      const writ = writs.find(w => w.id === id);
282	      if (!writ) return;
283	      const row = document.querySelector(`tr.writ-row[data-id="${id}"]`);
284	      if (!row) return;
285	      const cells = row.querySelectorAll('td');
286	      const actionsCell = cells[5];
287	      if (!actionsCell) return;
288	      actionsCell.innerHTML = rowActions(writ);
289	      actionsCell.querySelectorAll('.row-action-btn').forEach(btn => {
290	        btn.addEventListener('click', e => {
291	          e.stopPropagation();
292	          handleRowAction(btn.dataset.action, btn.dataset.id, btn);
293	        });
294	      });
295	    }
