298	
299	    function renderTable() {
300	      const tbody = document.getElementById('writ-tbody');
301	      const visible = sortedFilteredWrits();
302	
303	      if (visible.length === 0 && writs.length === 0) {
304	        tbody.innerHTML = `<tr><td colspan="6"><div class="empty-state">No writs found.</div></td></tr>`;
305	        return;
306	      }
307	
308	      tbody.innerHTML = '';
309	      for (const { writ: w, isChild } of visible) {
310	        const tr = document.createElement('tr');
311	        tr.className = 'writ-row' + (isChild ? ' child-row' : '');
312	        tr.dataset.id = w.id;
313	        tr.innerHTML =
314	          '<td>' + statusBadge(w.status) + '</td>' +
315	          '<td' + (isChild ? ' style="padding-left:2rem"' : '') + '>' + escHtml(w.title ?? '') + '</td>' +
316	          '<td>' + (w.type ?? '') + '</td>' +
317	          '<td class="id-cell"><code>' + w.id + '</code> <button class="btn copy-id-btn" data-copy-id="' + w.id + '" style="padding:0.1rem 0.3rem;font-size:0.7rem;cursor:pointer">📋</button></td>' +
318	          '<td>' + (isChild ? '' : fmtDate(w.createdAt)) + '</td>' +
319	          '<td class="row-actions" style="white-space:nowrap">' + rowActions(w) + '</td>';
320	
321	        // Wire row-action buttons (stop row-click propagation)
322	        tr.querySelectorAll('.row-action-btn').forEach(btn => {
323	          btn.addEventListener('click', e => {
324	            e.stopPropagation();
325	            handleRowAction(btn.dataset.action, btn.dataset.id, btn);
326	          });
327	        });
328	        // Stop propagation on the ID cell so clicking text or copy button doesn't open detail
329	        const idCell = tr.querySelector('.id-cell');
330	        if (idCell) {
331	          idCell.addEventListener('click', e => e.stopPropagation());
332	        }
333	        // Wire copy button in ID cell
334	        const copyBtn = tr.querySelector('.copy-id-btn');
335	        if (copyBtn) {
336	          copyBtn.addEventListener('click', () => {
337	            copyToClipboard(copyBtn.dataset.copyId, copyBtn);
338	          });
339	        }
340	        // Click row -> show detail view
341	        tr.addEventListener('click', () => showWritDetail(w.id));
342	        tbody.appendChild(tr);
343	      }
344	
345	      updateSortIndicators();
346	    }
