348	    async function copyToClipboard(text, feedbackEl) {
349	      try {
350	        await navigator.clipboard.writeText(text);
351	        const original = feedbackEl.textContent;
352	        feedbackEl.textContent = '✓';
353	        setTimeout(() => { feedbackEl.textContent = original; }, 1500);
354	      } catch (e) {
355	        console.error('Copy failed:', e);
356	      }
357	    }
358	
359	    function escHtml(s) {
360	      return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
361	    }
362	
363	    function escAttr(s) {
364	      return s.replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
365	    }
366	
367	    function updateSortIndicators() {
368	      document.querySelectorAll('.sort-ind').forEach(el => {
369	        const col = el.dataset.col;
