376	    function renderDetail(writ) {
377	      const isTerminal = ['completed', 'failed', 'cancelled'].includes(writ.status);
378	      const isDraft = writ.status === 'new';
379	      let html = '';
380	
381	      // Edit form — title and body are always editable; type and codex only for drafts
382	      html += `<div class="detail-section" id="edit-section-${writ.id}">`;
383	      html += `<h4>${isDraft ? 'Edit Draft' : 'Edit'}</h4>`;
384	      html += `<div class="form-row"><label>Title</label>`;
385	      html += `<input type="text" id="edit-title-${writ.id}" value="${escAttr(writ.title ?? '')}" style="padding:0.4rem 0.6rem;background:var(--bg3,#24283b);border:1px solid var(--border,#414868);border-radius:4px;color:inherit;font-size:0.9rem"></div>`;
386	      html += `<div class="form-row"><label>Body</label>`;
387	      html += `<textarea id="edit-body-${writ.id}" rows="8" style="padding:0.4rem 0.6rem;background:var(--bg3,#24283b);border:1px solid var(--border,#414868);border-radius:4px;color:inherit;font-size:0.9rem;resize:vertical;font-family:monospace">${escHtml(writ.body ?? '')}</textarea></div>`;
388	      if (isDraft) {
389	        html += `<div class="form-row"><label>Type</label>`;
390	        html += `<select id="edit-type-${writ.id}" style="padding:0.4rem 0.6rem;background:var(--bg3,#24283b);border:1px solid var(--border,#414868);border-radius:4px;color:inherit;font-size:0.9rem"></select></div>`;
391	        html += `<div class="form-row"><label>Codex</label>`;
392	        html += `<select id="edit-codex-${writ.id}" style="padding:0.4rem 0.6rem;background:var(--bg3,#24283b);border:1px solid var(--border,#414868);border-radius:4px;color:inherit;font-size:0.9rem"></select></div>`;
393	      }
394	      html += `<div class="action-buttons">`;
395	      html += `<button class="btn btn--primary" data-action="save-edit" data-id="${writ.id}">Save</button>`;
396	      html += `<div class="error-msg" id="edit-error-${writ.id}" style="display:none"></div>`;
397	      html += `<div class="warn-msg" id="edit-success-${writ.id}" style="display:none;color:var(--green,#9ece6a)"></div>`;
398	      html += `</div></div>`;
399	
400	      // Timestamps + metadata
401	      html += `<div class="detail-section"><h4>Details</h4><dl class="detail-grid">`;
402	      if (writ.codex) html += `<dt>Codex</dt><dd>${escHtml(writ.codex)}</dd>`;
403	      if (writ.parent) {
404	        html += `<dt>Parent</dt><dd><a href="?writ=${encodeURIComponent(writ.parent.id)}" style="color:var(--blue,#7aa2f7);text-decoration:underline;cursor:pointer">${escHtml(writ.parent.title)}</a> ${statusBadge(writ.parent.status)}</dd>`;
405	      }
406	      html += `<dt>Created</dt><dd>${fmtDate(writ.createdAt)}</dd>`;
407	      html += `<dt>Updated</dt><dd>${fmtDate(writ.updatedAt)}</dd>`;
408	      if (writ.resolvedAt) html += `<dt>Resolved</dt><dd>${fmtDate(writ.resolvedAt)}</dd>`;
409	      if (writ.resolution) html += `<dt>Resolution</dt><dd>${escHtml(writ.resolution)}</dd>`;
410	      html += `</dl></div>`;
411	
412	      // Transition actions
413	      if (!isTerminal) {
414	        html += `<div class="detail-section action-buttons" id="actions-${writ.id}">`;
415	        if (writ.status === 'new') {
416	          html += `<button class="btn btn--primary" data-action="publish" data-id="${writ.id}">Start (Publish)</button>`;
417	          html += `<button class="btn btn--danger" data-action="cancel" data-id="${writ.id}">Cancel</button>`;
418	        } else if (writ.status === 'open') {
419	          html += `<button class="btn btn--success" data-action="complete" data-id="${writ.id}">Complete</button>`;
420	          html += `<button class="btn btn--danger" data-action="fail" data-id="${writ.id}">Fail</button>`;
421	          html += `<button class="btn btn--danger" data-action="cancel" data-id="${writ.id}">Cancel</button>`;
422	        } else if (writ.status === 'stuck') {
423	          html += `<button class="btn btn--danger" data-action="fail" data-id="${writ.id}">Fail</button>`;
424	          html += `<button class="btn btn--danger" data-action="cancel" data-id="${writ.id}">Cancel</button>`;
