881	    async function loadWrits(replace = true) {
882	      if (replace) {
883	        offset = 0;
884	        writs = [];
885	        childrenMap = {};
886	      }
887	
888	      const params = new URLSearchParams({ limit: String(LIMIT), offset: String(offset) });
889	      if (currentStatus) params.set('status', currentStatus);
890	      if (currentType.size === 0) {
891	        // No types selected — show empty state without hitting the API
892	        if (replace) { writs = []; }
893	        renderTable();
894	        document.getElementById('load-more-row').style.display = 'none';
895	        return;
896	      }
897	      for (const t of currentType) {
898	        params.append('type', t);
899	      }
900	
901	      let result;
902	      try {
903	        result = await api('GET', `/api/writ/list?${params}`);
904	      } catch (e) {
905	        console.error('Failed to load writs:', e);
906	        return;
907	      }
908	
909	      // Partition: roots (no parentId) vs children (discarded)
910	      const roots = result.filter(w => !w.parentId);
911	
912	      if (replace) {
913	        writs = roots;
914	      } else {
915	        writs = writs.concat(roots);
916	      }
917	
918	      offset += result.length;
919	
920	      // Fetch all children for each newly loaded root
921	      await fetchChildrenForRoots(roots);
922	
923	      renderTable();
924	
925	      const loadMoreRow = document.getElementById('load-more-row');
926	      if (result.length < LIMIT) {
927	        loadMoreRow.style.display = 'none';
928	      } else {
929	        loadMoreRow.style.display = 'block';
930	      }
931	    }
