1123	    async function submitPostForm() {
1124	      const titleInput = document.getElementById('post-title-input');
1125	      const bodyInput = document.getElementById('post-body-input');
1126	      const typeSelect = document.getElementById('post-type-select');
1127	      const codexSelect = document.getElementById('post-codex-select');
1128	      const submitBtn = document.getElementById('post-submit-btn');
1129	      const errEl = document.getElementById('post-error');
1130	      const warnEl = document.getElementById('post-warn');
1131	
1132	      clearError(errEl);
1133	      clearError(warnEl);
1134	
1135	      const title = titleInput.value.trim();
1136	      const body = bodyInput.value.trim();
1137	      const type = typeSelect.value;
1138	      const codex = codexSelect.value || undefined;
1139	      const draft = document.getElementById('post-draft-checkbox').checked;
1140	
1141	      if (!title) { showError(errEl, 'Title is required.'); return; }
1142	      if (!body)  { showError(errEl, 'Body is required.'); return; }
1143	      if (!codex) { showError(errEl, 'A codex is required.'); codexSelect.focus(); return; }
1144	
1145	      submitBtn.disabled = true;
1146	      submitBtn.textContent = draft ? 'Saving Draft...' : 'Posting...';
1147	
1148	      try {
1149	        const payload = { title, body, type, ...(codex ? { codex } : {}), ...(draft ? { draft: true } : {}) };
1150	        const newWrit = await api('POST', '/api/commission/post', payload);
1151	
1152	        // If reposting, create retries link
1153	        if (repostSourceId) {
1154	          const srcId = repostSourceId;
1155	          repostSourceId = null;
1156	          try {
1157	            await api('POST', '/api/writ/link', { sourceId: newWrit.id, targetId: srcId, type: 'retries' });
1158	          } catch (le) {
1159	            warnEl.textContent = `Writ posted but link to original failed: ${le.message}. You can add the link manually.`;
1160	            warnEl.style.display = 'block';
1161	          }
1162	        }
1163	
1164	        clearPostForm();
1165	        closePostForm();
1166	        await loadWrits(true);
1167	      } catch (e) {
1168	        showError(errEl, e.message);
1169	      } finally {
1170	        submitBtn.disabled = false;
1171	        submitBtn.textContent = 'Post Writ';
1172	        document.getElementById('post-draft-checkbox').checked = false;
1173	      }
1174	    }
