1186	    function setTypeFilter(type) {
1187	      const bar = document.getElementById('type-filter-bar');
1188	      const allBtn = bar.querySelector('.type-filter-btn[data-type=""]');
1189	      const typeBtns = [...bar.querySelectorAll('.type-filter-btn:not([data-type=""])')];
1190	      const allTypeNames = typeBtns.map(b => b.dataset.type);
1191	
1192	      if (type === '') {
1193	        // "All" clicked: select all individual types
1194	        currentType = new Set(allTypeNames);
1195	      } else {
1196	        // Check if "All" is currently active (all types selected)
1197	        const allActive = allTypeNames.length > 0 && allTypeNames.every(t => currentType.has(t));
1198	        if (allActive) {
1199	          // "All" was active — deselect everything except the clicked type
1200	          currentType = new Set([type]);
1201	        } else {
1202	          // Normal toggle
1203	          if (currentType.has(type)) {
1204	            currentType.delete(type);
1205	          } else {
1206	            currentType.add(type);
1207	          }
1208	        }
1209	      }
1210	
1211	      // Update button visual state
1212	      const nowAllActive = allTypeNames.length > 0 && allTypeNames.every(t => currentType.has(t));
1213	      allBtn.classList.toggle('active-filter', nowAllActive);
1214	      typeBtns.forEach(btn => {
1215	        btn.classList.toggle('active-filter', currentType.has(btn.dataset.type));
1216	      });
1217	
1218	      loadWrits(true);
1219	    }
